import { EMPTY_SET, PLATFORM_FIELD_REGEXP } from '../const';
import { IdentifierType, SortExceptConfigType } from '../type';

/**
 * 空值转化为最小number
 * @return number
 */
export const emptyToMinNumber = (v?: IdentifierType) =>
    EMPTY_SET.has(v) || Number.isNaN(v) ? Number.MIN_SAFE_INTEGER : Number(v);

/**
 * 适用于columns中的排序sorter
 * @param dataIndex column中要比较的key
 * @param config 比较值配置，默认number比较
 */
export const sortExceptConfig: SortExceptConfigType = (dataIndex, config) => (a, b, sortOrder) => {
    const { noSortedValue = ' ', type = 'number', noSortedKey } = { ...config };
    if (a[`${noSortedKey}`] === noSortedValue || `${a[dataIndex]}` === `${noSortedValue}`)
        return +(sortOrder === 'ascend');
    if (type === 'number') return emptyToMinNumber(a[dataIndex]) - emptyToMinNumber(b[dataIndex]);
    return +(a[dataIndex] > b[dataIndex]);
};

/**
 * 放在table中的宽度，与`PLATFORM_FIELD_REGEXP`的推荐宽度搭配
 * @param width PLATFORM_FIELD_REGEXP or 其推荐宽度
 * @param {*} iconWidth icon宽度，默认0
 * @param {*} paddingWidth table的padding总占宽度，默认16
 */
export const toCellWidth = (
    width: number | (typeof PLATFORM_FIELD_REGEXP)[keyof typeof PLATFORM_FIELD_REGEXP],
    iconWidth = 0,
    paddingWidth = 16
) => (typeof width === 'number' ? width : width.recommendedWidth ?? 0) + iconWidth + paddingWidth;
